#include <stdio.h>
#include <string.h>

int main() {
    char t[200005], p[100005];

    // Read input
    fgets(t, 200005, stdin);
    fgets(p, 100005, stdin);

    // Remove trailing newline if present
    t[strcspn(t, "\n")] = '\0';
    p[strcspn(p, "\n")] = '\0';

    int n = strlen(t);
    int m = strlen(p);
    int cnt = 0;

    // Count overlapping occurrences
    for (int i = 0; i <= n - m; i++) {
        if (strncmp(t + i, p, m) == 0) {
            cnt++;
        }
    }

    printf("%d\n", cnt);
    return 0;
}
